logging.basicConfig(level=logging.INFO)
logger = logging.getLogger("MMOServer")


class ItemRarity(str, Enum):
    COMMON = "common"
    UNCOMMON = "uncommon"
    RARE = "rare"
    EPIC = "epic"
    LEGENDARY = "legendary"


@dataclass
class Item:
    item_id: str
    name: str
    rarity: ItemRarity
    owner_id: Optional[str] = None
    tradeable: bool = True
    stats: Dict = field(default_factory=dict)

    def to_dict(self):
        return {
            "item_id": self.item_id,
            "name": self.name,
            "rarity": self.rarity.value,
            "owner_id": self.owner_id,
            "tradeable": self.tradeable,
            "stats": self.stats,
        }


@dataclass
class TradeOffer:
    trade_id: str
    from_player_id: str
    to_player_id: str
    offered_items: list  # item_ids from initiator
    requested_items: list  # item_ids from target
    from_accepted: bool = False
    to_accepted: bool = False
    status: str = "pending"  # pending, accepted, rejected, cancelled, completed
    created_at: float = field(default_factory=time.time)

    def to_dict(self):
        return {
            "trade_id": self.trade_id,
            "from_player_id": self.from_player_id,
            "to_player_id": self.to_player_id,
            "offered_items": self.offered_items,
            "requested_items": self.requested_items,
            "from_accepted": self.from_accepted,
            "to_accepted": self.to_accepted,
            "status": self.status,
            "created_at": self.created_at,
        }


@dataclass
class Player:
    player_id: str
    username: str
    inventory: Dict[str, Item] = field(default_factory=dict)
    max_inventory_size: int = 50
    gold: int = 100
    websocket: Optional[object] = None
    active_trade_id: Optional[str] = None
    locked_items: Set[str] = field(default_factory=set)

    def to_dict(self):
        return {
            "player_id": self.player_id,
            "username": self.username,
            "inventory": {k: v.to_dict() for k, v in self.inventory.items()},
            "max_inventory_size": self.max_inventory_size,
            "gold": self.gold,
            "active_trade_id": self.active_trade_id,
        }


class InventoryManager:
    """Manages all inventory operations with concurrency safety."""

    def __init__(self):
        self._lock = asyncio.Lock()
        self._item_locks: Dict[str, asyncio.Lock] = {}
        self._player_locks: Dict[str, asyncio.Lock] = {}

    def _get_item_lock(self, item_id: str) -> asyncio.Lock:
        if item_id not in self._item_locks:
            self._item_locks[item_id] = asyncio.Lock()
        return self._item_locks[item_id]

    def _get_player_lock(self, player_id: str) -> asyncio.Lock:
        if player_id not in self._player_locks:
            self._player_locks[player_id] = asyncio.Lock()
        return self._player_locks[player_id]

    async def transfer_item(self, item: Item, from_player: Player, to_player: Player) -> bool:
        """Atomically transfer a single item between players."""
        # Always lock in sorted order to prevent deadlocks
        player_ids = sorted([from_player.player_id, to_player.player_id])
        lock1 = self._get_player_lock(player_ids[0])
        lock2 = self._get_player_lock(player_ids[1])

        async with lock1:
            async with lock2:
                # Validate
                if item.item_id not in from_player.inventory:
                    return False
                if not item.tradeable:
                    return False
                if len(to_player.inventory) >= to_player.max_inventory_size:
                    return False
                if item.item_id in from_player.locked_items:
                    return False

                # Execute transfer
                del from_player.inventory[item.item_id]
                item.owner_id = to_player.player_id
                to_player.inventory[item.item_id] = item
                return True

    async def transfer_items_batch(
        self,
        items_a_to_b: list,
        items_b_to_a: list,
        player_a: Player,
        player_b: Player,
        gold_a_to_b: int = 0,
        gold_b_to_a: int = 0,
    ) -> bool:
        """Atomically transfer batches of items between two players (for trades)."""
        player_ids = sorted([player_a.player_id, player_b.player_id])
        lock1 = self._get_player_lock(player_ids[0])
        lock2 = self._get_player_lock(player_ids[1])

        async with lock1:
            async with lock2:
                # Validate all items exist and are tradeable
                for item_id in items_a_to_b:
                    if item_id not in player_a.inventory:
                        return False
                    if not player_a.inventory[item_id].tradeable:
                        return False

                for item_id in items_b_to_a:
                    if item_id not in player_b.inventory:
                        return False
                    if not player_b.inventory[item_id].tradeable:
                        return False

                # Check inventory space
                net_a = len(items_b_to_a) - len(items_a_to_b)
                net_b = len(items_a_to_b) - len(items_b_to_a)

                if len(player_a.inventory) + net_a > player_a.max_inventory_size:
                    return False
                if len(player_b.inventory) + net_b > player_b.max_inventory_size:
                    return False

                # Check gold
                if player_a.gold < gold_a_to_b:
                    return False
                if player_b.gold < gold_b_to_a:
                    return False

                # Execute all transfers atomically
                moved_items_a = {}
                for item_id in items_a_to_b:
                    item = player_a.inventory.pop(item_id)
                    item.owner_id = player_b.player_id
                    moved_items_a[item_id] = item

                moved_items_b = {}
                for item_id in items_b_to_a:
                    item = player_b.inventory.pop(item_id)
                    item.owner_id = player_a.player_id
                    moved_items_b[item_id] = item

                player_b.inventory.update(moved_items_a)
                player_a.inventory.update(moved_items_b)

                # Transfer gold
                player_a.gold -= gold_a_to_b
                player_b.gold += gold_a_to_b
                player_b.gold -= gold_b_to_a
                player_a.gold += gold_b_to_a

                return True

    async def add_item_to_player(self, player: Player, item: Item) -> bool:
        lock = self._get_player_lock(player.player_id)
        async with lock:
            if len(player.inventory) >= player.max_inventory_size:
                return False
            item.owner_id = player.player_id
            player.inventory[item.item_id] = item
            return True

    async def remove_item_from_player(self, player: Player, item_id: str) -> Optional[Item]:
        lock = self._get_player_lock(player.player_id)
        async with lock:
            if item_id in player.inventory:
                item = player.inventory.pop(item_id)
                item.owner_id = None
                return item
            return None

    async def lock_items_for_trade(self, player: Player, item_ids: list) -> bool:
        lock = self._get_player_lock(player.player_id)
        async with lock:
            for item_id in item_ids:
                if item_id not in player.inventory:
                    return False
                if item_id in player.locked_items:
                    return False
            for item_id in item_ids:
                player.locked_items.add(item_id)
            return True

    async def unlock_items_for_trade(self, player: Player, item_ids: list):
        lock = self._get_player_lock(player.player_id)
        async with lock:
            for item_id in item_ids:
                player.locked_items.discard(item_id)


class GameServer:
    def __init__(self, host: str = "0.0.0.0", port: int = 8765):
        self.host = host
        self.port = port
        self.players: Dict[str, Player] = {}
        self.websocket_to_player: Dict[object, str] = {}
        self.trades: Dict[str, TradeOffer] = {}
        self.inventory_manager = InventoryManager()
        self._trade_lock = asyncio.Lock()
        self._item_templates = self._create_item_templates()

    def _create_item_templates(self) -> Dict[str, dict]:
        return {
            "iron_sword": {"name": "Iron Sword", "rarity": ItemRarity.COMMON, "stats": {"attack": 10}},
            "steel_shield": {"name": "Steel Shield", "rarity": ItemRarity.UNCOMMON, "stats": {"defense": 15}},
            "fire_staff": {"name": "Fire Staff", "rarity": ItemRarity.RARE, "stats": {"magic": 25, "attack": 5}},
            "dragon_helm": {"name": "Dragon Helm", "rarity": ItemRarity.EPIC, "stats": {"defense": 30, "hp": 50}},
            "excalibur": {"name": "Excalibur", "rarity": ItemRarity.LEGENDARY, "stats": {"attack": 100, "magic": 50}},
            "health_potion": {"name": "Health Potion", "rarity": ItemRarity.COMMON, "stats": {"heal": 50}},
            "mana_potion": {"name": "Mana Potion", "rarity": ItemRarity.COMMON, "stats": {"mana_restore": 30}},
            "golden_ring": {"name": "Golden Ring", "rarity": ItemRarity.UNCOMMON, "stats": {"luck": 10}},
            "shadow_cloak": {"name": "Shadow Cloak", "rarity": ItemRarity.RARE, "stats": {"stealth": 20, "defense": 10}},
            "soulbound_amulet": {
                "name": "Soulbound Amulet",
                "rarity": ItemRarity.LEGENDARY,
                "stats": {"all": 15},
                "tradeable": False,
            },
        }

    def create_item(self, template_key: str) -> Optional[Item]:
        if template_key not in self._item_templates:
            return None
        template = self._item_templates[template_key]
        return Item(
            item_id=str(uuid.uuid4()),
            name=template["name"],
            rarity=template["rarity"],
            stats=template.get("stats", {}),
            tradeable=template.get("tradeable", True),
        )

    async def send_message(self, websocket, msg_type: str, data: dict, success: bool = True):
        message = {"type": msg_type, "success": success, "data": data, "timestamp": time.time()}
        try:
            await websocket.send(json.dumps(message))
        except websockets.exceptions.ConnectionClosed:
            logger.warning("Failed to send message - connection closed")

    async def broadcast(self, msg_type: str, data: dict, exclude: Optional[str] = None):
        for player_id, player in self.players.items():
            if player_id != exclude and player.websocket:
                await self.send_message(player.websocket, msg_type, data)

    async def handle_login(self, websocket, data: dict):
        username = data.get("username", "").strip()
        if not username:
            await self.send_message(websocket, "login_response", {"error": "Username required"}, False)
            return

        # Check for duplicate username
        for p in self.players.values():
            if p.username == username and p.websocket is not None:
                await self.send_message(websocket, "login_response", {"error": "Username already taken"}, False)
                return

        player_id = str(uuid.uuid4())
        player = Player(player_id=player_id, username=username, websocket=websocket)

        # Give starter items
        starter_items = ["iron_sword", "health_potion", "health_potion", "mana_potion"]
        for template_key in starter_items:
            item = self.create_item(template_key)
            if item:
                await self.inventory_manager.add_item_to_player(player, item)

        self.players[player_id] = player
        self.websocket_to_player[websocket] = player_id

        logger.info(f"Player {username} ({player_id}) logged in")

        await self.send_message(websocket, "login_response", {
            "player": player.to_dict(),
            "message": f"Welcome, {username}!",
        })

        await self.broadcast("player_joined", {
            "player_id": player_id,
            "username": username,
        }, exclude=player_id)

    async def handle_get_inventory(self, websocket, data: dict):
        player_id = self.websocket_to_player.get(websocket)
        if not player_id:
            await self.send_message(websocket, "inventory_response", {"error": "Not logged in"}, False)
            return

        player = self.players[player_id]
        await self.send_message(websocket, "inventory_response", {
            "inventory": {k: v.to_dict() for k, v in player.inventory.items()},
            "gold": player.gold,
            "slots_used": len(player.inventory),
            "max_slots": player.max_inventory_size,
        })

    async def handle_get_players(self, websocket, data: dict):
        player_id = self.websocket_to_player.get(websocket)
        if not player_id:
            await self.send_message(websocket, "players_response", {"error": "Not logged in"}, False)
            return

        online_players = [
            {"player_id": p.player_id, "username": p.username}
            for p in self.players.values()
            if p.websocket is not None and p.player_id != player_id
        ]
        await self.send_message(websocket, "players_response", {"players": online_players})

    async def handle_spawn_item(self, websocket, data: dict):
        """Debug/admin command to spawn items."""
        player_id = self.websocket_to_player.get(websocket)
        if not player_id:
            await self.send_message(websocket, "spawn_response", {"error": "Not logged in"}, False)
            return

        template_key = data.get("template")
        if not template_key:
            await self.send_message(websocket, "spawn_response", {
                "error": "Template required",
                "available_templates": list(self._item_templates.keys()),
            }, False)
            return

        item = self.create_item(template_key)
        if not item:
            await self.send_message(websocket, "spawn_response", {
                "error": f"Unknown template: {template_key}",
                "available_templates": list(self._item_templates.keys()),
            }, False)
            return

        player = self.players[player_id]
        success = await self.inventory_manager.add_item_to_player(player, item)
        if success:
            logger.info(f"Spawned {item.name} for {player.username}")
            await self.send_message(websocket, "spawn_response", {
                "item": item.to_dict(),
                "message": f"Spawned {item.name}",
            })
        else:
            await self.send_message(websocket, "spawn_response", {"error": "Inventory full"}, False)

    async def handle_drop_item(self, websocket, data: dict):
        player_id = self.websocket_to_player.get(websocket)
        if not player_id:
            await self.send_message(websocket, "drop_response", {"error": "Not logged in"}, False)
            return

        item_id = data.get("item_id")
        if not item_id:
            await self.send_message(websocket, "drop_response", {"error": "item_id required"}, False)
            return

        player = self.players[player_id]
        if item_id in player.locked_items:
            await self.send_message(websocket, "drop_response", {"error": "Item is locked in a trade"}, False)
            return

        item = await self.inventory_manager.remove_item_from_player(player, item_id)
        if item:
            logger.info(f"Player {player.username} dropped {item.name}")
            await self.send_message(websocket, "drop_response", {
                "item": item.to_dict(),
                "message": f"Dropped {item.name}",
            })
        else:
            await self.send_message(websocket, "drop_response", {"error": "Item not found"}, False)

    async def handle_trade_request(self, websocket, data: dict):
        player_id = self.websocket_to_player.get(websocket)
        if not player_id:
            await self.send_message(websocket, "trade_response", {"error": "Not logged in"}, False)
            return

        target_id = data.get("target_player_id")
        offered_items = data.get("offered_items", [])
        requested_items = data.get("requested_items", [])

        if not target_id:
            await self.send_message(websocket, "trade_response", {"error": "target_player_id required"}, False)
            return

        if target_id == player_id:
            await self.send_message(websocket, "trade_response", {"error": "Cannot trade with yourself"}, False)
            return

        if target_id not in self.players or self.players[target_id].websocket is None:
            await self.send_message(websocket, "trade_response", {"error": "Target player not found or offline"}, False)
            return

        from_player = self.players[player_id]
        to_player = self.players[target_id]

        async with self._trade_lock:
            # Check neither player is in an active trade
            if from_player.active_trade_id:
                await self.send_message(websocket, "trade_response", {"error": "You are already in a trade"}, False)
                return
            if to_player.active_trade_id:
                await self.send_message(websocket, "trade_response", {"error": "Target player is already in a trade"}, False)
                return

            # Validate offered items exist and are tradeable
            for item_id in offered_items:
                if item_id not in from_player.inventory:
                    await self.send_message(websocket, "trade_response", {"error": f"You don't have item {item_id}"}, False)
                    return
                if not from_player.inventory[item_id].tradeable:
                    await self.send_message(websocket, "trade_response", {"error": f"Item {item_id} is not tradeable"}, False)
                    return

            # Validate requested items exist
            for item_id in requested_items:
                if item_id not in to_player.inventory:
                    await self.send_message(websocket, "trade_response", {"error": f"Target doesn't have item {item_id}"}, False)
                    return
                if not to_player.inventory[item_id].tradeable:
                    await self.send_message(websocket, "trade_response", {"error": f"Item {item_id} is not tradeable"}, False)
                    return

            # Lock items
            lock_a = await self.inventory_manager.lock_items_for_trade(from_player, offered_items)
            if not lock_a:
                await self.send_message(websocket, "trade_response", {"error": "Failed to lock your items"}, False)
                return

            lock_b = await self.inventory_manager.lock_items_for_trade(to_player, requested_items)
            if not lock_b:
                await self.inventory_manager.unlock_items_for_trade(from_player, offered_items)
                await self.send_message(websocket, "trade_response", {"error": "Failed to lock target items"}, False)
                return

            trade_id = str(uuid.uuid4())
            trade = TradeOffer(
                trade_id=trade_id,
                from_player_id=player_id,
                to_player_id=target_id,
                offered_items=offered_items,
                requested_items=requested_items,
                from_accepted=True,  # Initiator implicitly accepts their own offer
            )
            self.trades[trade_id] = trade
            from_player.active_trade_id = trade_id
            to_player.active_trade_id = trade_id

        logger.info(f"Trade {trade_id} created: {from_player.username} -> {to_player.username}")

        offered_details = [from_player.inventory[iid].to_dict() for iid in offered_items if iid in from_player.inventory]
        requested_details = [to_player.inventory[iid].to_dict() for iid in requested_items if iid in to_player.inventory]

        await self.send_message(websocket, "trade_response", {
            "trade": trade.to_dict(),
            "message": f"Trade request sent to {to_player.username}",
        })

        # Notify the target player
        await self.send_message(to_player.websocket, "trade_incoming", {
            "trade": trade.to_dict(),
            "from_username": from_player.username,
            "offered_items_detail": offered_details,
            "requested_items_detail": requested_details,
            "message": f"{from_player.username} wants to trade with you!",
        })

    async def handle_trade_accept(self, websocket, data: dict):
        player_id = self.websocket_to_player.get(websocket)
        if not player_id:
            await self.send_message(websocket, "trade_accept_response", {"error": "Not logged in"}, False)
            return

        trade_id = data.get("trade_id")
        if not trade_id or trade_id not in self.trades:
            await self.send_message(websocket, "trade_accept_response", {"error": "Invalid trade"}, False)
            return

        trade = self.trades[trade_id]

        if trade.status != "pending":
            await self.send_message(websocket, "trade_accept_response", {"error": f"Trade is {trade.status}"}, False)
            return

        if player_id not in (trade.from_player_id, trade.to_player_id):
            await self.send_message(websocket, "trade_accept_response", {"error": "You are not part of this trade"}, False)
            return

        async with self._trade_lock:
            if player_id == trade.from_player_id:
                trade.from_accepted = True
            else:
                trade.to_accepted = True

            if trade.from_accepted and trade.to_accepted:
                # Execute the trade
                from_player = self.players[trade.from_player_id]
                to_player = self.players[trade.to_player_id]

                # Unlock items before transfer
                await self.inventory_manager.unlock_items_for_trade(from_player, trade.offered_items)
                await self.inventory_manager.unlock_items_for_trade(to_player, trade.requested_items)

                success = await self.inventory_manager.transfer_items_batch(
                    items_a_to_b=trade.offered_items,
                    items_b_to_a=trade.requested_items,
                    player_a=from_player,
                    player_b=to_player,
                )

                if success:
                    trade.status = "completed"
                    from_player.active_trade_id = None
                    to_player.active_trade_id = None

                    logger.info(f"Trade {trade_id} completed between {from_player.username} and {to_player.username}")

                    result_data = {
                        "trade": trade.to_dict(),
                        "message": "Trade completed successfully!",
                    }

                    await self.send_message(from_player.websocket, "trade_completed", result_data)
                    await self.send_message(to_player.websocket, "trade_completed", result_data)
                else:
                    trade.status = "failed"
                    from_player.active_trade_id = None
                    to_player.active_trade_id = None

                    await self.send_message(from_player.websocket, "trade_failed", {"error": "Trade execution failed"}, False)
                    await self.send_message(to_player.websocket, "trade_failed", {"error": "Trade execution failed"}, False)

                del self.trades[trade_id]
                return

        await self.send_message(websocket, "trade_accept_response", {
            "trade": trade.to_dict(),
            "message": "You accepted the trade. Waiting for the other player.",
        })

    async def handle_trade_reject(self, websocket, data: dict):
        player_id = self.websocket_to_player.get(websocket)
        if not player_id:
            await self.send_message(websocket, "trade_reject_response", {"error": "Not logged in"}, False)
            return

        trade_id = data.get("trade_id")
        if not trade_id or trade_id not in self.trades:
            await self.send_message(websocket, "trade_reject_response", {"error": "Invalid trade"}, False)
            return

        trade = self.trades[trade_id]

        if player_id not in (trade.from_player_id, trade.to_player_id):
            await self.send_message(websocket, "trade_reject_response", {"error": "You are not part of this trade"}, False)
            return

        async with self._trade_lock:
            trade.status = "rejected"
            from_player = self.players[trade.from_player_id]
            to_player = self.players[trade.to_player_id]

            # Unlock items
            await self.inventory_manager.unlock_items_for_trade(from_player, trade.offered_items)
            await self.inventory_manager.unlock_items_for_trade(to_player, trade.requested_items)

            from_player.active_trade_id = None
            to_player.active_trade_id = None

            rejector = self.players[player_id]
            other_id = trade.to_player_id if player_id == trade.from_player_id else trade.from_player_id
            other_player = self.players[other_id]

            logger.info(f"Trade {trade_id} rejected by {rejector.username}")

            await self.send_message(websocket, "trade_reject_response", {
                "trade": trade.to_dict(),
                "message": "Trade rejected.",
            })

            if other_player.websocket:
                await self.send_message(other_player.websocket, "trade_rejected", {
                    "trade": trade.to_dict(),
                    "message": f"{rejector.username} rejected the trade.",
                })

            del self.trades[trade_id]

    async def handle_trade_cancel(self, websocket, data: dict):
        player_id = self.websocket_to_player.get(websocket)
        if not player_id:
            await self.send_message(websocket, "trade_cancel_response", {"error": "Not logged in"}, False)
            return

        trade_id = data.get("trade_id")
        if not trade_id or trade_id not in self.trades:
            await self.send_message(websocket, "trade_cancel_response", {"error": "Invalid trade"}, False)
            return

        trade = self.trades[trade_id]

        if player_id not in (trade.from_player_id, trade.to_player_id):
            await self.send_message(websocket, "trade_cancel_response", {"error": "You are not part of this trade"}, False)
            return

        async with self._trade_lock:
            trade.status = "cancelled"
            from_player = self.players[trade.from_player_id]
            to_player = self.players[trade.to_player_id]

            await self.inventory_manager.unlock_items_for_trade(from_player, trade.offered_items)
            await self.inventory_manager.unlock_items_for_trade(to_player, trade.requested_items)

            from_player.active_trade_id = None
            to_player.active_trade_id = None

            canceller = self.players[player_id]
            other_id = trade.to_player_id if player_id == trade.from_player_id else trade.from_player_id
            other_player = self.players[other_id]

            logger.info(f"Trade {trade_id} cancelled by {canceller.username}")

            await self.send_message(websocket, "trade_cancel_response", {
                "trade": trade.to_dict(),
                "message": "Trade cancelled.",
            })

            if other_player.websocket:
                await self.send_message(other_player.websocket, "trade_cancelled", {
                    "trade": trade.to_dict(),
                    "message": f"{canceller.username} cancelled the trade.",
                })

            del self.trades[trade_id]

    async def handle_give_item(self, websocket, data: dict):
        """Direct item transfer (gift) from one player to another."""
        player_id = self.websocket_to_player.get(websocket)
        if not player_id:
            await self.send_message(websocket, "give_response", {"error": "Not logged in"}, False)
            return

        item_id = data.get("item_id")
        target_id = data.get("target_player_id")

        if not item_id or not target_id:
            await self.send_message(websocket, "give_response", {"error": "item_id and target_player_id required"}, False)
            return

        if target_id == player_id:
            await self.send_message(websocket, "give_response", {"error": "Cannot give to yourself"}, False)
            return

        if target_id not in self.players or self.players[target_id].websocket is None:
            await self.send_message(websocket, "give_response", {"error": "Target player not found or offline"}, False)
            return

        from_player = self.players[player_id]
        to_player = self.players[target_id]

        if item_id not in from_player.inventory:
            await self.send_message(websocket, "give_response", {"error": "Item not found"}, False)
            return

        if item_id in from_player.locked_items:
            await self.send_message(websocket, "give_response", {"error": "Item is locked in a trade"}, False)
            return

        item = from_player.inventory[item_id]
        success = await self.inventory_manager.transfer_item(item, from_player, to_player)

        if success:
            logger.info(f"{from_player.username} gave {item.name} to {to_player.username}")

            await self.send_message(websocket, "give_response", {
                "item": item.to_dict(),
                "target_username": to_player.username,
                "message": f"Gave {item.name} to {to_player.username}",
            })

            await self.send_message(to_player.websocket, "item_received", {
                "item": item.to_dict(),
                "from_username": from_player.username,
                "message": f"{from_player.username} gave you {item.name}!",
            })
        else:
            await self.send_message(websocket, "give_response", {"error": "Transfer failed"}, False)

    async def handle_inspect_player(self, websocket, data: dict):
        """View another player's tradeable inventory."""
        player_id = self.websocket_to_player.get(websocket)
        if not player_id:
            await self.send_message(websocket, "inspect_response", {"error": "Not logged in"}, False)
            return

        target_id = data.get("target_player_id")
        if not target_id or target_id not in self.players:
            await self.send_message(websocket, "inspect_response", {"error": "Player not found"}, False)
            return

        target = self.players[target_id]
        tradeable_items = {
            k: v.to_dict() for k, v in target.inventory.items()
            if v.tradeable and k not in target.locked_items
        }

        await self.send_message(websocket, "inspect_response", {
            "player_id": target_id,
            "username": target.username,
            "tradeable_items": tradeable_items,
        })

    async def cleanup_player(self, websocket):
        player_id = self.websocket_to_player.get(websocket)
        if not player_id:
            return

        player = self.players.get(player_id)
        if not player:
            return

        # Cancel any active trade
        if player.active_trade_id and player.active_trade_id in self.trades:
            trade = self.trades[player.active_trade_id]
            async with self._trade_lock:
                trade.status = "cancelled"
                from_player = self.players.get(trade.from_player_id)
                to_player = self.players.get(trade.to_player_id)

                if from_player:
                    await self.inventory_manager.unlock_items_for_trade(from_player, trade.offered_items)
                    from_player.active_trade_id = None
                if to_player:
                    await self.inventory_manager.unlock_items_for_trade(to_player, trade.requested_items)
                    to_player.active_trade_id = None

                other_id = trade.to_player_id if player_id == trade.from_player_id else trade.from_player_id
                other_player = self.players.get(other_id)
                if other_player and other_player.websocket:
                    await self.send_message(other_player.websocket, "trade_cancelled", {
                        "trade": trade.to_dict(),
                        "message": f"{player.username} disconnected. Trade cancelled.",
                    })

                if player.active_trade_id in self.trades:
                    del self.trades[player.active_trade_id]

        player.websocket = None
        del self.websocket_to_player[websocket]

        logger.info(f"Player {player.username} ({player_id}) disconnected")

        await self.broadcast("player_left", {
            "player_id": player_id,
            "username": player.username,
        })

    async def handle_message(self, websocket, message: str):
        try:
            data = json.loads(message)
        except json.JSONDecodeError:
            await self.send_message(websocket, "error", {"error": "Invalid JSON"}, False)
            return

        msg_type = data.get("type")
        payload = data.get("data", {})

        handlers = {
            "login": self.handle_login,
            "get_inventory": self.handle_get_inventory,
            "get_players": self.handle_get_players,
            "spawn_item": self.handle_spawn_item,
            "drop_item": self.handle_drop_item,
            "give_item": self.handle_give_item,
            "inspect_player": self.handle_inspect_player,
            "trade_request": self.handle_trade_request,
            "trade_accept": self.handle_trade_accept,
            "trade_reject": self.handle_trade_reject,
            "trade_cancel": self.handle_trade_cancel,
        }

        handler = handlers.get(msg_type)
        if handler:
            await handler(websocket, payload)
        else:
            await self.send_message(websocket, "error", {
                "error": f"Unknown message type: {msg_type}",
                "available_types": list(handlers.keys()),
            }, False)

    async def connection_handler(self, websocket, path=None):
        logger.info(f"New connection from {websocket.remote_address}")
        try:
            async for message in websocket:
                await self.handle_message(websocket, message)
        except websockets.exceptions.ConnectionClosed as e:
            logger.info(f"Connection closed: {e}")
        finally:
            await self.cleanup_player(websocket)

    async def trade_timeout_checker(self):
        """Periodically check for stale trades and cancel them."""
        while True:
            await asyncio.sleep(30)
            now = time.time()
            stale_trades = []

            for trade_id, trade in self.trades.items():
                if trade.status == "pending" and now - trade.created_at > 120:  # 2 min timeout
                    stale_trades.append(trade_id)

            for trade_id in stale_trades:
                if trade_id in self.trades:
                    trade = self.trades[trade_id]
                    async with self._trade_lock:
                        trade.status = "cancelled"
                        from_player = self.players.get(trade.from_player_id)
                        to_player = self.players.get(trade.to_player_id)

                        if from_player:
                            await self.inventory_manager.unlock_items_for_trade(from_player, trade.offered_items)
                            from_player.active_trade_id = None
                            if from_player.websocket:
                                await self.send_message(from_player.websocket, "trade_cancelled", {
                                    "trade": trade.to_dict(),
                                    "message": "Trade timed out.",
                                })

                        if to_player:
                            await self.inventory_manager.unlock_items_for_trade(to_player, trade.requested_items)
                            to_player.active_trade_id = None
                            if to_player.websocket:
                                await self.send_message(to_player.websocket, "trade_cancelled", {
                                    "trade": trade.to_dict(),
                                    "message": "Trade timed out.",
                                })

                        del self.trades[trade_id]
                        logger.info(f"Trade {trade_id} timed out and was cancelled")

    async def start(self):
        logger.info(f"Starting MMO Game Server on {self.host}:{self.port}")
        logger.info("Supported actions: login, get_inventory, get_players, spawn_item, drop_item, "
                     "give_item, inspect_player, trade_request, trade_accept, trade_reject, trade_cancel")

        # Start the timeout checker
        asyncio.create_task(self.trade_timeout_checker())

        async with websockets.serve(self.connection_handler, self.host, self.port):
            logger.info(f"Server running on ws://{self.host}:{self.port}")
            await asyncio.Future()  # Run forever


if __name__ == "__main__":
    server = GameServer(host="0.0.0.0", port=8765)
    asyncio.run(server.start())